ShellPythonNode.JS Curl <pre><code>curl --request GET \
--url https://kekkai-api.redume.su/api/getChart/week?from_currency=RUB&amp;conv_currency=USD
</code></pre> Request <pre><code>import requests

res = requests.get('https://kekkai-api.redume.su/api/getChart/week', {
    'from_currency': 'USD',
    'conv_currency': 'RUB',
}, timeout=3)

print(res.json())
</code></pre> Axios <pre><code>const axios = require('axios');

axios.get('https://kekkai-api.redume.su/api/getChart/week', {
    timeout: 3000,
    'from_currency': 'USD',
    'conv_currency': 'RUB',  
})
    .then((res) =&gt; {
        console.log(res['data']);
    })
    .catch((err) =&gt; {
        console.error(err);
    });
</code></pre>

